package com.payment.module

sealed class PaymentResult<out T> {
    data class Success<T>(val data: T) : PaymentResult<T>()
    data class Error(val code: Int, val message: String, val exception: Throwable? = null) : PaymentResult<Nothing>()
    data object Loading : PaymentResult<Nothing>()

    val isSuccess get() = this is Success
    val isError get() = this is Error

    fun <R> map(transform: (T) -> R): PaymentResult<R> = when (this) {
        is Success -> Success(transform(data))
        is Error -> this
        is Loading -> Loading
    }

    fun onSuccess(action: (T) -> Unit): PaymentResult<T> {
        if (this is Success) action(data)
        return this
    }

    fun onError(action: (Int, String, Throwable?) -> Unit): PaymentResult<T> {
        if (this is Error) action(code, message, exception)
        return this
    }
}

